async (params, browser) => {
  // Search Product Hunt
  await browser.open(`https://www.producthunt.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'post\'], [data-test=\'post-item\'], [class*=\'ProductItem\'], a[href*=\'/posts/\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[class*="post-item"], [data-test="post-item"], [class*="ProductItem"], div[class*="styles_item"]'); if (items.length === 0) { const altItems = document.querySelectorAll('a[href*="/posts/"]'); const seen = new Set(); for (let i = 0; i < Math.min(altItems.length, 15); i++) { const el = altItems[i]; const href = el.getAttribute('href') || ''; if (seen.has(href)) continue; seen.add(href); const titleEl = el.querySelector('h3, strong, [class*="title"]'); const taglineEl = el.querySelector('p, [class*="tagline"]'); const imgEl = el.querySelector('img'); results.push({ name: titleEl ? titleEl.textContent.trim() : el.textContent.trim().substring(0, 100), tagline: taglineEl ? taglineEl.textContent.trim() : '', url: href.startsWith('http') ? href : 'https://www.producthunt.com' + href, image: imgEl ? imgEl.getAttribute('src') : '' }); } } else { for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const nameEl = el.querySelector('h3, strong, [class*="title"], [data-test="post-name"]'); const taglineEl = el.querySelector('p, [class*="tagline"], [data-test="post-tagline"]'); const upvotesEl = el.querySelector('[class*="vote"] span, [class*="upvote"] span, button[class*="vote"] span'); const commentsEl = el.querySelector('[class*="comment"] span, a[href*="#comments"] span'); const linkEl = el.querySelector('a[href*="/posts/"]'); const imgEl = el.querySelector('img[src*="ph-files"], img[src*="producthunt"], img'); const topicEls = el.querySelectorAll('[class*="topic"] a, [class*="tag"] a'); const topics = []; topicEls.forEach(function(t) { topics.push(t.textContent.trim()); }); results.push({ name: nameEl ? nameEl.textContent.trim() : '', tagline: taglineEl ? taglineEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', comments: commentsEl ? commentsEl.textContent.trim() : '', topics: topics.slice(0, 3), image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
